package com.i2i.voltwise.audit; import com.i2i.voltwise.home.Home; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name="recommendations") public class Recommendation { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) public Long id; @ManyToOne(optional=false,fetch=FetchType.LAZY) @JoinColumn(name="home_id") public Home home; @Column(nullable=false,columnDefinition="text") public String content; @Column(name="delivery_status",nullable=false) public String deliveryStatus; @Column(name="created_at",nullable=false) public Instant createdAt; protected Recommendation(){} public Recommendation(Home h,String c,String status){home=h;content=c;deliveryStatus=status;createdAt=Instant.now();} }
